    geocode_lng = null, geocode_maps_url = '', geocode_confidence = 'low', address_check_html = '';

if (!leadData.caller_address || leadData.caller_address.trim().length < 5) {
  geocode_status = 'not_provided';
  address_check_html = '<span style="color:#718096">— Not provided</span>';
} else if (geoResponse.status === 'OK' && geoResponse.results && geoResponse.results.length > 0) {
  const top = geoResponse.results[0];
  geocode_formatted = top.formatted_address;
  geocode_lat = top.geometry.location.lat;
  geocode_lng = top.geometry.location.lng;
  geocode_maps_url = 'https://maps.google.com/?q=' + encodeURIComponent(geocode_formatted);
  const types = top.types || [];
  if (types.includes('street_address') || types.includes('premise') || types.includes('subpremise')) {
    geocode_status = 'verified'; geocode_confidence = 'high';
    address_check_html = '<span style="color:#38a169;font-weight:600">✅ Verified</span> — ' + geocode_formatted + ' &nbsp;<a href="' + geocode_maps_url + '" style="color:#6C63FF;text-decoration:none;font-weight:600">📍 View Map</a>';
  } else if (types.includes('route') || types.includes('intersection')) {
    geocode_status = 'partial'; geocode_confidence = 'medium';
    address_check_html = '<span style="color:#d69e2e;font-weight:600">⚠️ Partial match</span> — ' + geocode_formatted + ' &nbsp;<a href="' + geocode_maps_url + '" style="color:#6C63FF;text-decoration:none">📍 View Map</a>';
