    geocode_status = 'unverified'; geocode_confidence = 'low';
    address_check_html = '<span style="color:#e53e3e;font-weight:600">⚠️ Unverified</span> — Closest: ' + geocode_formatted + '. Confirm with caller.';
  }
} else if (geoResponse.status === 'ZERO_RESULTS') {
  geocode_status = 'not_found';
  address_check_html = '<span style="color:#e53e3e;font-weight:600">❌ Not found</span> — Confirm address with caller before dispatching.';
} else {
  geocode_status = 'error';
  address_check_html = '<span style="color:#718096">⚠️ Could not verify — confirm with caller</span>';
