const scoreColor = score >= 8 ? '#dc2626' : score >= 6 ? '#d97706' : '#718096';
const score_badge = '<span style="background:' + (score >= 8 ? '#fef2f2' : score >= 6 ? '#fffbeb' : '#f9fafb') + ';color:' + scoreColor + ';border:2px solid ' + scoreColor + ';border-radius:20px;padding:3px 12px;font-weight:700;font-size:15px">' + score + '/10</span>';

// ── URGENCY BADGE ─────────────────────────────────────────────────────────────
const urgency = leadData.urgency || 'Medium';
const urgencyColor = urgency === 'Emergency' ? '#dc2626' : urgency === 'High' ? '#d97706' : urgency === 'Medium' ? '#2563eb' : '#718096';
const urgency_badge = '<span style="color:' + urgencyColor + ';font-weight:600">' + urgency + '</span>';

