const sentimentColor = sentiment <= 2 ? '#dc2626' : sentiment === 3 ? '#6b7280' : '#16a34a';

// ── DURATION ──────────────────────────────────────────────────────────────────
const dur = leadData.duration_seconds || 0;
const duration_formatted = dur >= 60 ? Math.floor(dur/60) + 'm ' + (dur%60) + 's' : dur + 's';

// ── SMS TEXT ──────────────────────────────────────────────────────────────────
// Rich SMS with all key flags — keeps it scannable on a phone
const tierEmoji = callTier === 'Emergency' ? '🚨' : callTier === 'Urgent' ? '⚡' : '📋';
const vulnFlag  = vulnerable ? ' VULNERABLE' : '';
const repeatFlag = ''; // populated later by repeat caller check
const notifyType = leadData.notify_type || 'lead';
const sms_header = notifyType === 'emergency'
  ? 'EMERGENCY' + vulnFlag
  : notifyType === 'customer_query'
  ? 'CUSTOMER QUERY'
  : 'NEW LEAD';
const addrShort = geocode_status === 'verified' ? geocode_formatted : (leadData.caller_address || 'No address');
