  + 'Name: ' + (leadData.caller_name || 'Unknown') + '\n'
  + 'Ph: ' + (leadData.caller_phone || leadData.from_number || 'N/A') + '\n'
  + 'Addr: ' + addrShort + '\n'
  + (leadData.service_requested || 'General') + ' | ' + jobType + ' | Score: ' + score + '/10';

// ── EMAIL HTML ────────────────────────────────────────────────────────────────
const notifyTypeForEmail = leadData.notify_type || 'lead';
const isEmergencyEmail = notifyTypeForEmail === 'emergency';
const accentColor = isEmergencyEmail ? '#dc2626' : '#6C63FF';
